import{_ as t,c as h,a1 as i,o as c}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Giới thiệu về Bảo mật Thông tin & Kiểm thử Xâm nhập","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/0-core-knowledge/4-Infosec-101.md","filePath":"vi/categories/ethical-hacking-labs/0-core-knowledge/4-Infosec-101.md"}'),a={name:"vi/categories/ethical-hacking-labs/0-core-knowledge/4-Infosec-101.md"};function o(l,n,g,r,u,s){return c(),h("div",null,n[0]||(n[0]=[i('<h1 id="gioi-thieu-ve-bao-mat-thong-tin-kiem-thu-xam-nhap" tabindex="-1"><u>Giới thiệu về Bảo mật Thông tin &amp; Kiểm thử Xâm nhập</u> <a class="header-anchor" href="#gioi-thieu-ve-bao-mat-thong-tin-kiem-thu-xam-nhap" aria-label="Permalink to &quot;&lt;u&gt;Giới thiệu về Bảo mật Thông tin &amp; Kiểm thử Xâm nhập&lt;/u&gt;&quot;">​</a></h1><blockquote><p>⚠️ Module này hoàn toàn lý thuyết và được trích xuất từ repo <a href="https://github.com/Samsar4/CEH-v10-Study-Guide/" target="_blank" rel="noreferrer">CEH Study Guide</a>. Ở đây bạn sẽ tìm thấy một số thuật ngữ cơ bản trong &#39;thế giới InfoSec&#39;.</p></blockquote><h2 id="cac-khai-niem-bao-mat-co-ban" tabindex="-1"><u> Các Khái niệm Bảo mật Cơ bản </u> <a class="header-anchor" href="#cac-khai-niem-bao-mat-co-ban" aria-label="Permalink to &quot;&lt;u&gt; Các Khái niệm Bảo mật Cơ bản &lt;/u&gt;&quot;">​</a></h2><p>Toàn bộ nguyên tắc là tránh <strong>Trộm cắp, Giả mạo và Gián đoạn</strong> của hệ thống thông qua <strong>Bộ ba CIA</strong> (Bảo mật, Toàn vẹn và Sẵn sàng).</p><p align="center"><img width="50%" src="https://i.ytimg.com/vi/AJTJN4wDBM8/hqdefault.jpg"></p><ul><li><p><strong>Bảo mật (Confidentiality)</strong> Ngăn hệ thống và dữ liệu bị truy cập, xem, đọc bởi bất kỳ ai không được phép.</p></li><li><p><strong>Toàn vẹn (Integrity)</strong> Bảo vệ dữ liệu khỏi bị sửa đổi hoặc xóa bởi bên không được phép, và đảm bảo rằng khi người được phép thực hiện thay đổi không nên được thực hiện thì thiệt hại có thể được khắc phục.</p></li><li><p><strong>Sẵn sàng (Availability)</strong> Hệ thống, kênh truy cập và cơ chế xác thực phải hoạt động đúng để thông tin chúng cung cấp và bảo vệ có sẵn khi cần.</p></li></ul><p><strong>Lưu ý:</strong> <em>Ngoài ra, các thuộc tính khác, chẳng hạn như tính xác thực, trách nhiệm giải trình, không từ chối và độ tin cậy cũng có thể được bao gồm. (ISO/IEC 27000:2009)</em></p><ul><li><p><strong>Kiểm toán &amp; Trách nhiệm giải trình (Auditing &amp; Accountability)</strong> Về cơ bản theo dõi mọi thứ, như, ai đã đăng nhập khi nào họ đăng nhập ai truy cập dữ liệu này.</p></li><li><p><strong>Không từ chối (Non-Repudiation)</strong> Không từ chối là sự đảm bảo rằng ai đó không thể phủ nhận tính hợp lệ của điều gì đó. Không từ chối là một khái niệm pháp lý được sử dụng rộng rãi trong bảo mật thông tin và đề cập đến một dịch vụ, cung cấp bằng chứng về nguồn gốc dữ liệu và tính toàn vẹn của dữ liệu.</p></li></ul><h3 id="can-bang-bao-mat-chuc-nang-va-kha-nang-su-dung" tabindex="-1"><strong>Cân bằng Bảo mật, Chức năng và Khả năng sử dụng</strong> <a class="header-anchor" href="#can-bang-bao-mat-chuc-nang-va-kha-nang-su-dung" aria-label="Permalink to &quot;**Cân bằng Bảo mật, Chức năng và Khả năng sử dụng**&quot;">​</a></h3><p>Có sự phụ thuộc lẫn nhau giữa ba thuộc tính này. Khi <strong>bảo mật tăng lên, khả năng sử dụng và chức năng giảm xuống</strong>. Bất kỳ tổ chức nào cũng nên cân bằng giữa ba phẩm chất này để đạt được hệ thống thông tin cân bằng.</p><p align="center"><img width="50%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f14455ed4def635e1bc93b85657f43dbbf4a3127/triad2.png"></p><h2 id="cac-loai-hacker" tabindex="-1"><u>Các loại Hacker</u> <a class="header-anchor" href="#cac-loai-hacker" aria-label="Permalink to &quot;&lt;u&gt;Các loại Hacker&lt;/u&gt;&quot;">​</a></h2><p align="center"><img width="50%" src="https://www.simplilearn.com/ice9/free_resources_article_thumb/types-hacker.JPG"></p><blockquote><ul><li><strong>Black Hat</strong> - Hacker tìm cách thực hiện các hoạt động độc hại.</li><li><strong>Gray Hat</strong> - Hacker thực hiện hoạt động tốt hoặc xấu nhưng không có sự cho phép của tổ chức mà họ đang hack.</li><li><strong>White Hat</strong> - Hacker đạo đức; Họ sử dụng kỹ năng để cải thiện bảo mật bằng cách phát hiện lỗ hổng trước hacker độc hại.</li></ul></blockquote><p><strong>Script Kiddie / Skiddies</strong> - Cá nhân không có kỹ năng sử dụng các script hoặc chương trình độc hại, chẳng hạn như web shell, được phát triển bởi người khác để tấn công hệ thống máy tính và mạng và phá hoại trang web.</p><p><strong>Hacker được nhà nước tài trợ (State-Sponsored Hacker)</strong> - Hacker được thuê bởi chính phủ hoặc thực thể liên quan.</p><p><strong>Hacktivist</strong> - Người hack cho một mục đích; chương trình nghị sự chính trị.</p><p><strong>Hacker tự sát (Suicide Hackers)</strong> - Là những hacker không sợ đi tù hoặc đối mặt với bất kỳ hình phạt nào; hack để hoàn thành công việc.</p><p><strong>Khủng bố mạng (Cyberterrorist)</strong> - Được thúc đẩy bởi niềm tin tôn giáo hoặc chính trị để tạo ra sự sợ hãi hoặc gián đoạn.</p><h2 id="tu-vung-hacking" tabindex="-1"><u>Từ vựng Hacking</u> <a class="header-anchor" href="#tu-vung-hacking" aria-label="Permalink to &quot;&lt;u&gt;Từ vựng Hacking&lt;/u&gt;&quot;">​</a></h2><ul><li><strong>Giá trị hack (Hack value)</strong> - Giá trị hoặc giá trị được nhận thức của mục tiêu theo cách nhìn của kẻ tấn công.</li><li><strong>Lỗ hổng (Vulnerability)</strong> - Khiếm khuyết hệ thống, điểm yếu trên hệ thống (trong thiết kế, triển khai, v.v.).</li><li><strong>Mối đe dọa (Threat)</strong> - Khai thác một lỗ hổng.</li><li><strong>Khai thác (Exploit)</strong> - Exploit là cách để có được quyền truy cập vào hệ thống thông qua một lỗi bảo mật và tận dụng lỗi đó cho lợi ích của họ.</li><li><strong>Tải trọng (Payload)</strong> - Thành phần của cuộc tấn công; là phần văn bản riêng tư của người dùng cũng có thể chứa phần mềm độc hại như worm hoặc virus thực hiện hành động độc hại; xóa dữ liệu, gửi spam hoặc mã hóa dữ liệu.</li><li><strong>Tấn công zero-day</strong> - Cuộc tấn công xảy ra trước khi nhà cung cấp biết hoặc có thể vá lỗi.</li><li><strong>Daisy Chaining / Pivotting</strong> - Bao gồm việc có được quyền truy cập vào mạng và/hoặc máy tính và sau đó sử dụng cùng thông tin để có quyền truy cập vào nhiều mạng và máy tính chứa thông tin mong muốn.</li><li><strong>Doxxing</strong> - Công bố PII về một cá nhân thường với ý đồ xấu.</li><li><strong>Kiến trúc Bảo mật Thông tin Doanh nghiệp (EISA - Enterprise Information Security Architecture)</strong> - xác định cấu trúc và hành vi của hệ thống thông tin tổ chức thông qua các quy trình, yêu cầu, nguyên tắc và mô hình.</li></ul><h2 id="cac-loai-moi-đe-doa" tabindex="-1"><u> Các loại Mối đe dọa </u> <a class="header-anchor" href="#cac-loai-moi-đe-doa" aria-label="Permalink to &quot;&lt;u&gt; Các loại Mối đe dọa &lt;/u&gt;&quot;">​</a></h2><ul><li><p><strong>Mối đe dọa Mạng</strong></p><ul><li>Thu thập thông tin</li><li>Nghe lén và theo dõi</li><li>Đầu độc DNS/ARP</li><li>MITM (Tấn công trung gian)</li><li>DoS/DDoS</li><li>Tấn công dựa trên mật khẩu</li><li>Tấn công Firewall và IDS</li><li>Đánh cắp phiên</li></ul></li><li><p><strong>Mối đe dọa Máy chủ</strong></p><ul><li>Bẻ khóa mật khẩu</li><li>Tấn công phần mềm độc hại</li><li>Footprinting</li><li>Lập hồ sơ</li><li>Thực thi mã tùy ý</li><li>Truy cập backdoor</li><li>Leo thang đặc quyền</li><li>Thực thi mã</li></ul></li><li><p><strong>Mối đe dọa Ứng dụng</strong></p><ul><li>Tấn công Injection</li><li>Xác thực dữ liệu/đầu vào không đúng</li><li>Xử lý lỗi và quản lý ngoại lệ không đúng</li><li>Manipulation trường ẩn</li><li>Quản lý phiên bị hỏng</li><li>Vấn đề mật mã</li><li>SQL injection</li><li>Lừa đảo phishing</li><li>Tràn bộ đệm</li><li>Tiết lộ thông tin</li><li>Cấu hình sai bảo mật</li></ul></li></ul><h2 id="vecto-tan-cong" tabindex="-1"><u> Vectơ Tấn công </u> <a class="header-anchor" href="#vecto-tan-cong" aria-label="Permalink to &quot;&lt;u&gt; Vectơ Tấn công &lt;/u&gt;&quot;">​</a></h2><p><em>Con đường mà hacker có thể truy cập vào máy chủ để gửi tải trọng hoặc kết quả độc hại</em></p><ul><li><p><strong>APT - Mối đe dọa Dai dẳng Nâng cao (Advanced Persistent Threats)</strong></p><ul><li>Một mối đe dọa dai dẳng nâng cao là một tác nhân đe dọa lén lút, thường là quốc gia hoặc nhóm được nhà nước tài trợ, có được quyền truy cập trái phép vào mạng máy tính và không bị phát hiện trong thời gian dài; Thường sử dụng tấn công zero-day.</li></ul></li><li><p><strong>Điện toán đám mây / Công nghệ dựa trên đám mây</strong></p><ul><li>Lỗ hổng trong ứng dụng đám mây của một khách hàng cho phép kẻ tấn công truy cập dữ liệu của khách hàng khác</li></ul></li><li><p><strong>Virus, worm và phần mềm độc hại</strong></p><ul><li>Virus và worm là mối đe dọa mạng phổ biến nhất có khả năng lây nhiễm mạng trong vài giây.</li></ul></li><li><p><strong>Ransomware</strong></p><ul><li>Hạn chế truy cập vào các tệp và thư mục của hệ thống máy tính và yêu cầu thanh toán tiền chuộc trực tuyến cho kẻ tấn công để loại bỏ các hạn chế.</li></ul></li><li><p><strong>Mối đe dọa thiết bị di động</strong></p></li><li><p><strong>Botnet</strong></p><ul><li>Mạng khổng lồ gồm các hệ thống bị xâm phạm được sử dụng bởi kẻ xâm nhập để thực hiện nhiều cuộc tấn công mạng khác nhau</li></ul></li><li><p><strong>Tấn công nội bộ</strong></p><ul><li>Nhân viên bất mãn có thể gây thiệt hại tài sản từ bên trong.</li><li>Mạng khổng lồ gồm các máy chủ bị xâm phạm. (dùng cho DDoS).</li></ul></li><li><p><strong>Tấn công phishing</strong></p></li><li><p><strong>Mối đe dọa ứng dụng web</strong></p><ul><li>Các tấn công như SQL injection, XSS (Cross-site scripting)...</li></ul></li><li><p><strong>Mối đe dọa IoT</strong></p></li></ul><h2 id="cac-loai-tan-cong" tabindex="-1"><u>Các loại Tấn công</u> <a class="header-anchor" href="#cac-loai-tan-cong" aria-label="Permalink to &quot;&lt;u&gt;Các loại Tấn công&lt;/u&gt;&quot;">​</a></h2><h3 id="_1-he-đieu-hanh" tabindex="-1">1. Hệ điều hành <a class="header-anchor" href="#_1-he-đieu-hanh" aria-label="Permalink to &quot;1. Hệ điều hành&quot;">​</a></h3><p><em>Các tấn công nhắm vào lỗi hệ điều hành hoặc vấn đề bảo mật bên trong như tài khoản khách hoặc mật khẩu mặc định.</em></p><blockquote><ul><li><strong>Vectơ</strong>: Tràn bộ đệm, Triển khai Giao thức, lỗi phần mềm, mức độ vá, sơ đồ xác thực</li></ul></blockquote><h3 id="_2-ung-dung" tabindex="-1">2. Ứng dụng <a class="header-anchor" href="#_2-ung-dung" aria-label="Permalink to &quot;2. Ứng dụng&quot;">​</a></h3><p><em>Các tấn công vào mã lập trình và logic phần mềm.</em></p><blockquote><ul><li><strong>Vectơ</strong>: Tràn bộ đệm, Bug, XSS, DoS, SQL Injection, MitM</li></ul></blockquote><h3 id="_3-cau-hinh-sai" tabindex="-1">3. Cấu hình sai <a class="header-anchor" href="#_3-cau-hinh-sai" aria-label="Permalink to &quot;3. Cấu hình sai&quot;">​</a></h3><p><em>Tấn công tận dụng các hệ thống bị cấu hình sai do cấu hình không đúng hoặc cấu hình mặc định.</em></p><blockquote><ul><li><strong>Ví dụ</strong>: Quyền không đúng của người dùng SQL; Access-list cho phép tất cả</li></ul></blockquote><h3 id="_4-ma-shrink-wrap" tabindex="-1">4. Mã Shrink-Wrap <a class="header-anchor" href="#_4-ma-shrink-wrap" aria-label="Permalink to &quot;4. Mã Shrink-Wrap&quot;">​</a></h3><p><em>Hành động khai thác lỗ hổng trong phần mềm chưa được vá hoặc cấu hình kém.</em></p><blockquote><ul><li><strong>Ví dụ</strong>: Lỗi phần mềm trong phiên bản 1.0; Lỗi trong script CGI mẫu; Mật khẩu mặc định</li></ul></blockquote><h2 id="lo-hong" tabindex="-1"><u>Lỗ hổng</u> <a class="header-anchor" href="#lo-hong" aria-label="Permalink to &quot;&lt;u&gt;Lỗ hổng&lt;/u&gt;&quot;">​</a></h2><ul><li><strong>CVSS - Hệ thống chấm điểm lỗ hổng phổ biến (Common Vulnerability Scoring System)</strong> <a href="https://nvd.nist.gov/vuln-metrics/cvss" target="_blank" rel="noreferrer">[+]</a><ul><li>Đặt điểm số dựa trên mức độ nghiêm trọng</li><li><img src="https://3.bp.blogspot.com/-5V1cb_wTvsk/Wl78iF4Sd8I/AAAAAAAAF7U/KmK4pMXi54YworDgh4uI8aZtHgy0bbznQCLcBGAs/s1600/CVSS.png" alt="cvss"></li></ul></li><li><strong>CVE – Lỗ hổng và Tiêu lộ phổ biến (Common Vulnerabilities and Exposures)</strong> <a href="https://cve.mitre.org/" target="_blank" rel="noreferrer">[+]</a><ul><li>Là danh sách các lỗ hổng và tiêu lộ được công bố công khai được duy trì bởi MITRE.</li><li><img src="https://i0.wp.com/gbhackers.com/wp-content/uploads/2016/10/cve.png?resize=486%2C408&amp;ssl=1" alt="cve"></li></ul></li><li><strong>NVD - Cơ sở dữ liệu Lỗ hổng Quốc gia (National Vulnerability Database)</strong> <a href="https://nvd.nist.gov/" target="_blank" rel="noreferrer">[+]</a><ul><li>là cơ sở dữ liệu, được duy trì bởi NIST, đồng bộ hóa hoàn toàn với danh sách MITRE CVE; Kho lưu trữ lỗ hổng của chính phủ Mỹ.</li></ul></li></ul><h3 id="cac-loai-lo-hong" tabindex="-1">Các loại Lỗ hổng <a class="header-anchor" href="#cac-loai-lo-hong" aria-label="Permalink to &quot;Các loại Lỗ hổng&quot;">​</a></h3><ul><li><strong>Cấu hình sai</strong> - cấu hình không đúng dịch vụ hoặc ứng dụng</li><li><strong>Cài đặt mặc định</strong> - không thay đổi cài đặt trong ứng dụng có sẵn theo mặc định</li><li><strong>Tràn bộ đệm</strong> - lỗi thực thi mã</li><li><strong>Thiếu bản vá</strong> - hệ thống chưa được vá</li><li><strong>Lỗi thiết kế</strong> - lỗi cố hữu trong thiết kế hệ thống như mã hóa và xác thực dữ liệu</li><li><strong>Lỗi hệ điều hành</strong> - lỗi cụ thể cho từng hệ điều hành</li><li><strong>Mật khẩu mặc định</strong> - để mật khẩu mặc định đi kèm với hệ thống/ứng dụng</li></ul><h2 id="cac-giai-đoan-kiem-thu-xam-nhap-phuong-phap-ceh" tabindex="-1"><u>Các giai đoạn Kiểm thử Xâm nhập (Phương pháp CEH)</u> <a class="header-anchor" href="#cac-giai-đoan-kiem-thu-xam-nhap-phuong-phap-ceh" aria-label="Permalink to &quot;&lt;u&gt;Các giai đoạn Kiểm thử Xâm nhập (Phương pháp CEH)&lt;/u&gt;&quot;">​</a></h2><ol><li><strong>Giai đoạn Tiền tấn công</strong> - Do thám và thu thập dữ liệu.</li><li><strong>Giai đoạn Tấn công</strong> - Cố gắng xâm nhập mạng và thực hiện tấn công.</li><li><strong>Giai đoạn Sau tấn công</strong> - Dọn dẹp để đưa hệ thống về trạng thái trước tấn công và cung cấp báo cáo.</li></ol><h2 id="nam-giai-đoan-cua-hacking-đao-đuc" tabindex="-1"><u>Năm Giai đoạn của Hacking Đạo đức</u> <a class="header-anchor" href="#nam-giai-đoan-cua-hacking-đao-đuc" aria-label="Permalink to &quot;&lt;u&gt;Năm Giai đoạn của Hacking Đạo đức&lt;/u&gt;&quot;">​</a></h2><h3 id="_1-do-tham-reconnaissance" tabindex="-1">1. <strong>Do thám (Reconnaissance)</strong> <a class="header-anchor" href="#_1-do-tham-reconnaissance" aria-label="Permalink to &quot;1. **Do thám (Reconnaissance)**&quot;">​</a></h3><p><em>Thu thập bằng chứng về mục tiêu</em>; Có hai loại Do thám:</p><ul><li><strong>Do thám Thụ động (Passive Reconnaissance)</strong>: Thu thập thông tin về máy tính và mạng mục tiêu <strong>mà không tương tác trực tiếp với hệ thống</strong>. <ul><li>Ví dụ: Tìm kiếm Google, Hồ sơ công khai, Phát hành mới, Mạng xã hội, Quét mạng xung quanh.</li></ul></li><li><strong>Do thám Chủ động (Active Reconnaissance)</strong>: Bao gồm tương tác trực tiếp với mục tiêu. <ul><li>Ví dụ: Gọi điện thoại cho mục tiêu, Phỏng vấn việc làm; các công cụ như Nmap, Nessus, OpenVAS, Nikto và Metasploit có thể được coi là Do thám Chủ động.</li></ul></li></ul><h3 id="_2-quet-liet-ke-scanning-enumeration" tabindex="-1">2. <strong>Quét &amp; Liệt kê (Scanning &amp; Enumeration)</strong> <a class="header-anchor" href="#_2-quet-liet-ke-scanning-enumeration" aria-label="Permalink to &quot;2. **Quét &amp; Liệt kê (Scanning &amp; Enumeration)**&quot;">​</a></h3><p><em>Thu thập thông tin chuyên sâu hơn về mục tiêu.</em></p><ul><li>Ví dụ: Quét mạng, Quét cổng, Phiên bản dịch vụ nào đang chạy.</li></ul><h3 id="_3-chiem-quyen-truy-cap-gaining-access" tabindex="-1">3. <strong>Chiếm quyền truy cập (Gaining Access)</strong> <a class="header-anchor" href="#_3-chiem-quyen-truy-cap-gaining-access" aria-label="Permalink to &quot;3. **Chiếm quyền truy cập (Gaining Access)**&quot;">​</a></h3><p><em>Các cuộc tấn công được tiến hành để có quyền truy cập vào hệ thống.</em></p><ul><li>Ví dụ: Có thể được thực hiện cục bộ (ngoại tuyến), qua LAN hoặc qua internet. <ul><li>Ví dụ(2): Giả mạo để khai thác hệ thống bằng cách giả vờ là người dùng hợp pháp hoặc hệ thống khác, chúng có thể gửi gói dữ liệu chứa lỗi đến hệ thống mục tiêu để khai thác lỗ hổng.</li><li>Có thể được thực hiện bằng nhiều kỹ thuật như injection lệnh, tràn bộ đệm, DoS, bẻ khóa thông tin đăng nhập, kỹ thuật xã hội, cấu hình sai, v.v.</li></ul></li></ul><h3 id="_4-duy-tri-truy-cap-maintaining-access" tabindex="-1">4. <strong>Duy trì truy cập (Maintaining Access)</strong> <a class="header-anchor" href="#_4-duy-tri-truy-cap-maintaining-access" aria-label="Permalink to &quot;4. **Duy trì truy cập (Maintaining Access)**&quot;">​</a></h3><p><em>Các mục được đặt để đảm bảo truy cập trong tương lai.</em></p><ul><li>Ví dụ: Rootkit, Trojan, Backdoor có thể được sử dụng.</li></ul><h3 id="_5-xoa-dau-vet-covering-tracks" tabindex="-1">5. <strong>Xóa dấu vết (Covering Tracks)</strong> <a class="header-anchor" href="#_5-xoa-dau-vet-covering-tracks" aria-label="Permalink to &quot;5. **Xóa dấu vết (Covering Tracks)**&quot;">​</a></h3><p><em>Các bước thực hiện để che giấu thành công và xâm nhập; Không bị phát hiện.</em></p><ul><li>Ví dụ: Xóa nhật ký; Làm mờ trojan hoặc chương trình backdoor độc hại.</li></ul><h2 id="ba-loai-phong-thu-chu-đong" tabindex="-1">Ba loại Phòng thủ Chủ động <a class="header-anchor" href="#ba-loai-phong-thu-chu-đong" aria-label="Permalink to &quot;Ba loại Phòng thủ Chủ động&quot;">​</a></h2><ul><li><strong>Quấy rối (Annoyance)</strong><ul><li>Bao gồm theo dõi hacker và dẫn hắn vào máy chủ giả, lãng phí thời gian của hắn — và khiến hắn dễ bị phát hiện.</li></ul></li><li><strong>Truy nguyên (Attribution)</strong><ul><li>Xác định kẻ tấn công; Sử dụng công cụ để truy vết nguồn gốc cuộc tấn công đến vị trí cụ thể, hoặc thậm chí một hacker cá nhân.</li></ul></li><li><strong>Tấn công (Attack)</strong><ul><li>Điều gây tranh cãi nhất. Để &quot;hack lại&quot;, một công ty truy cập vào máy tính của hacker bị cáo buộc để xóa dữ liệu hoặc thậm chí trả thù. Cả hai bước này đều bị coi là bất hợp pháp.</li></ul></li></ul><h2 id="đam-bao-thong-tin-ia" tabindex="-1"><u> Đảm bảo Thông tin (IA) </u> <a class="header-anchor" href="#đam-bao-thong-tin-ia" aria-label="Permalink to &quot;&lt;u&gt; Đảm bảo Thông tin (IA) &lt;/u&gt;&quot;">​</a></h2><p><em>Đề cập đến sự đảm bảo về Tính toàn vẹn, Sẵn sàng, Bảo mật và Tính xác thực của thông tin và hệ thống thông tin trong quá trình sử dụng, xử lý, lưu trữ và truyền tải thông tin.</em></p><ul><li><strong>Các quy trình giúp đạt được IA:</strong><ul><li>Phát triển chính sách, quy trình và hướng dẫn cục bộ.</li><li>Thiết kế chiến lược xác thực mạng và người dùng.</li><li>Xác định lỗ hổng và mối đe dọa mạng (Đánh giá lỗ hổng phác thảo tư thế bảo mật của mạng).</li><li>Xác định vấn đề và yêu cầu tài nguyên.</li><li>Tạo kế hoạch cho các yêu cầu tài nguyên đã xác định.</li><li>Áp dụng các kiểm soát IA phù hợp.</li><li>Thực hiện quy trình C&amp;A (Chứng nhận và Công nhận) của hệ thống thông tin giúp theo dõi lỗ hổng và triển khai biện pháp an toàn.</li><li>Cung cấp đào tạo đảm bảo thông tin cho tất cả nhân viên trong tổ chức liên bang và tư nhân.</li></ul></li></ul><h2 id="chuong-trinh-quan-ly-bao-mat-thong-tin" tabindex="-1"><u>Chương trình Quản lý Bảo mật Thông tin </u> <a class="header-anchor" href="#chuong-trinh-quan-ly-bao-mat-thong-tin" aria-label="Permalink to &quot;&lt;u&gt;Chương trình Quản lý Bảo mật Thông tin &lt;/u&gt;&quot;">​</a></h2><p><em>Sự kết hợp của chính sách, quy trình, thủ tục, tiêu chuẩn và hướng dẫn để thiết lập <strong>mức độ bảo mật thông tin cần thiết.</strong></em></p><ul><li>Được thiết kế để đảm bảo doanh nghiệp hoạt động trong trạng thái giảm thiểu rủi ro.</li><li>Nó bao gồm tất cả các quy trình tổ chức và vận hành cũng như người tham gia liên quan đến bảo mật thông tin.</li></ul><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/950220d4b802bb726fe84470c7a13055b056a621/infosec.jpg" alt="infosec"></p><blockquote><p>⚠️ <strong>IA</strong> tập trung vào đánh giá rủi ro, phía giảm thiểu; ⚠️ <strong>InfoSec</strong> tập trung vào thực sự triển khai các biện pháp bảo mật để bảo vệ hệ thống.</p></blockquote><h2 id="eisa-kien-truc-bao-mat-thong-tin-doanh-nghiep" tabindex="-1"><u>EISA - Kiến trúc Bảo mật Thông tin Doanh nghiệp</u> <a class="header-anchor" href="#eisa-kien-truc-bao-mat-thong-tin-doanh-nghiep" aria-label="Permalink to &quot;&lt;u&gt;EISA - Kiến trúc Bảo mật Thông tin Doanh nghiệp&lt;/u&gt;&quot;">​</a></h2><p><em>Tập hợp các yêu cầu, quy trình, nguyên tắc và mô hình xác định cấu trúc và hành vi của hệ thống thông tin tổ chức.</em></p><ul><li><strong>Mục tiêu của EISA</strong>: <ul><li>Hỗ trợ giám sát và phát hiện hành vi mạng</li><li>Phát hiện và phục hồi từ vi phạm bảo mật</li><li>Ưu tiên tài nguyên của tổ chức</li><li>Hỗ trợ thực hiện đánh giá rủi ro của tài sản CNTT tổ chức.</li><li>Triển vọng chi phí khi được tích hợp trong các điều khoản bảo mật như ứng phó sự cố, phục hồi thảm họa, tương quan sự kiện, v.v.</li></ul></li></ul><h2 id="kiem-soat-bao-mat-vat-ly" tabindex="-1"><u>Kiểm soát Bảo mật Vật lý</u> <a class="header-anchor" href="#kiem-soat-bao-mat-vat-ly" aria-label="Permalink to &quot;&lt;u&gt;Kiểm soát Bảo mật Vật lý&lt;/u&gt;&quot;">​</a></h2><ul><li><p><strong>Kiểm soát phòng ngừa</strong>: Ngăn cản tác nhân thực hiện mối đe dọa.</p><ul><li>Ví dụ: Hàng rào, Khóa máy chủ, Cửa bẫy, v.v.</li></ul></li><li><p><strong>Kiểm soát phát hiện</strong>: Nhận ra mối đe dọa của tác nhân.</p><ul><li>Ví dụ: Kiểm tra lý lịch, CCTV.</li></ul></li><li><p><strong>Kiểm soát ngăn chặn</strong>: Ngăn cản tác nhân <strong>cố gắng</strong> thực hiện mối đe dọa.</p><ul><li>Ví dụ: Biển cảnh báo.</li></ul></li><li><p><strong>Phục hồi</strong>: Giảm thiểu tác động của mối đe dọa đã hiện thực hóa.</p><ul><li>Ví dụ: Sao lưu.</li></ul></li><li><p><strong>Kiểm soát bù trừ</strong>: Cung cấp sửa chữa thay thế cho bất kỳ chức năng nào ở trên.</p></li></ul><p><em>Hầu hết các kiểm soát bảo mật là kiểm soát giai đoạn phòng ngừa</em>.</p><p>⚠️ <strong>Phòng thủ theo chiều sâu (Defense in Depth)</strong>: Nhiều lớp kiểm soát bảo mật; Cung cấp dự phòng trong trường hợp kiểm soát thất bại. (ví dụ: hình dưới)</p><p><img src="https://www.fairwarning.com/wp-content/uploads/2019/03/Defense-in-Depth-for-Cloud-Security-Rainbow-Diagram.png" alt="defense-in-depth"></p><h3 id="cac-loai-kiem-soat-bao-mat" tabindex="-1">Các loại Kiểm soát Bảo mật <a class="header-anchor" href="#cac-loai-kiem-soat-bao-mat" aria-label="Permalink to &quot;Các loại Kiểm soát Bảo mật&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mô tả</th><th>Ví dụ</th></tr></thead><tbody><tr><td><strong>Vật lý</strong></td><td>Bảo vệ, đèn, camera, bình chữa cháy, bảo vệ lũ lụt</td></tr><tr><td><strong>Hành chính</strong></td><td>Đào tạo nhận thức, chính sách, thủ tục và hướng dẫn cho infosec</td></tr><tr><td><strong>Kỹ thuật</strong></td><td>IDS/IPS, Firewall, Mã hóa, Thẻ thông minh, Danh sách kiểm soát truy cập</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Mô tả</th><th>Ví dụ</th></tr></thead><tbody><tr><td><strong>Phòng ngừa</strong></td><td>Xác thực, chuông báo động</td></tr><tr><td><strong>Phát hiện</strong></td><td>Kiểm toán, Sao lưu</td></tr><tr><td><strong>Khắc phục</strong></td><td>Phục hồi hoạt động</td></tr></tbody></table><h2 id="quan-ly-rui-ro" tabindex="-1"><u>Quản lý Rủi ro</u> <a class="header-anchor" href="#quan-ly-rui-ro" aria-label="Permalink to &quot;&lt;u&gt;Quản lý Rủi ro&lt;/u&gt;&quot;">​</a></h2><p><strong>Rủi ro</strong> có thể được định nghĩa là xác suất xảy ra một mối đe dọa hoặc sự kiện có thể gây thiệt hại, hoặc gây mất mát hoặc có tác động tiêu cực khác từ các nghĩa vụ nội bộ hoặc bên ngoài.</p><h3 id="ma-tran-rui-ro" tabindex="-1">Ma trận rủi ro <a class="header-anchor" href="#ma-tran-rui-ro" aria-label="Permalink to &quot;Ma trận rủi ro&quot;">​</a></h3><p><strong>Ma trận rủi ro</strong> được sử dụng trong quá trình <strong>đánh giá rủi ro</strong> để xác định mức độ rủi ro bằng cách xem xét loại <strong>xác suất hoặc khả năng</strong> so với loại <strong>mức độ nghiêm trọng</strong> của hậu quả.</p><ul><li>Đây là cơ chế đơn giản để tăng khả năng hiển thị của rủi ro và hỗ trợ ra quyết định của quản lý.</li></ul><p><img src="https://paladinrisk.com.au/wp-content/uploads/2018/11/risk-1-1024x434.jpg" alt="matrix"></p><h3 id="quan-ly-rui-ro-1" tabindex="-1">Quản lý Rủi ro <a class="header-anchor" href="#quan-ly-rui-ro-1" aria-label="Permalink to &quot;Quản lý Rủi ro&quot;">​</a></h3><p><em>Là việc xác định, đánh giá và ưu tiên rủi ro theo sau là ứng dụng có điều phối và tiết kiệm tài nguyên để giảm thiểu, giám sát và kiểm soát xác suất hoặc tác động của các sự kiện không may hoặc để tối đa hóa hiện thực hóa cơ hội.</em></p><h2 id="chinh-sach-bao-mat" tabindex="-1"><u>Chính sách Bảo mật</u> <a class="header-anchor" href="#chinh-sach-bao-mat" aria-label="Permalink to &quot;&lt;u&gt;Chính sách Bảo mật&lt;/u&gt;&quot;">​</a></h2><ol><li><strong>Chính sách</strong> - Tuyên bố cấp cao về bảo vệ thông tin; Quy tắc kinh doanh để bảo vệ bộ ba CIA; Chính sách bảo mật có thể được áp dụng cho Người dùng, Hệ thống, Đối tác, Mạng và Nhà cung cấp. <ul><li><strong>Ví dụ Chính sách Bảo mật phổ biến:</strong><ul><li>Chính sách mật khẩu <ul><li>Đáp ứng yêu cầu độ phức tạp mật khẩu.</li><li>Ví dụ: Độ dài tối thiểu 8 ký tự, chữ hoa chữ thường và chữ số.</li></ul></li><li>Chính sách bảo mật không dây</li><li>AUP - Chính sách Sử dụng Chấp nhận được <ul><li>Cách sử dụng đúng tài sản của công ty</li><li>Ví dụ: &quot;Nên và không nên&quot; với máy tính công ty.</li></ul></li><li>Chính sách Lưu giữ Dữ liệu <ul><li>Ví dụ: Giữ dữ liệu trong X thời gian.</li></ul></li><li>Chính sách Kiểm soát Truy cập <ul><li>Ví dụ: Truy cập máy chủ; Firewall</li></ul></li></ul></li></ul></li><li><strong>Thủ tục</strong> - Tập hợp các bước chi tiết để hoàn thành mục tiêu; Hướng dẫn thực hiện</li><li><strong>Hướng dẫn</strong> - Lời khuyên về hành động trong tình huống nhất định; Được khuyến nghị, không bắt buộc</li></ol><h2 id="chinh-sach-bao-mat-vi-du" tabindex="-1">Chính sách Bảo mật - Ví dụ <a class="header-anchor" href="#chinh-sach-bao-mat-vi-du" aria-label="Permalink to &quot;Chính sách Bảo mật - Ví dụ&quot;">​</a></h2><ul><li><p><strong>Chính sách Kiểm soát Truy cập</strong></p><ul><li>Điều này xác định các tài nguyên được bảo vệ và các quy tắc kiểm soát truy cập vào chúng</li></ul></li><li><p><strong>Chính sách Truy cập Từ xa</strong></p><ul><li>Điều này xác định ai có thể có truy cập từ xa và xác định phương tiện truy cập và kiểm soát bảo mật truy cập từ xa.</li></ul></li><li><p><strong>Chính sách Quản lý Firewall</strong></p><ul><li>Điều này xác định truy cập, quản lý và giám sát firewall trong tổ chức.</li></ul></li><li><p><strong>Chính sách Kết nối Mạng</strong></p><ul><li>Điều này xác định ai có thể cài đặt tài nguyên mới trên mạng, phê duyệt cài đặt thiết bị mới, ghi lại thay đổi mạng, v.v.</li></ul></li><li><p><strong>Chính sách Mật khẩu</strong></p><ul><li>Điều này xác định hướng dẫn sử dụng bảo vệ mật khẩu mạnh trên các tài nguyên có sẵn.</li></ul></li><li><p><strong>Chính sách Tài khoản Người dùng</strong></p><ul><li>Điều này xác định quy trình tạo tài khoản, quyền hạn, quyền và trách nhiệm của tài khoản người dùng.</li></ul></li><li><p><strong>Chính sách Bảo vệ Thông tin</strong></p><ul><li>Điều này xác định mức độ nhạy cảm của thông tin, ai có thể truy cập, cách lưu trữ và truyền tải, và cách xóa khỏi phương tiện lưu trữ, v.v.</li></ul></li><li><p><strong>Chính sách Truy cập Đặc biệt</strong></p><ul><li>Điều này xác định các điều khoản và điều kiện cấp truy cập đặc biệt vào tài nguyên hệ thống.</li></ul></li><li><p><strong>Chính sách Bảo mật Email</strong></p><ul><li>Chính sách này được thiết kế để điều chỉnh việc sử dụng đúng email công ty.</li></ul></li><li><p><strong>Chính sách Sử dụng Chấp nhận được</strong></p><ul><li>Điều này xác định việc sử dụng chấp nhận được của tài nguyên hệ thống.</li></ul></li></ul><h2 id="chinh-sach-bao-mat-cac-loai" tabindex="-1">Chính sách Bảo mật - Các loại <a class="header-anchor" href="#chinh-sach-bao-mat-cac-loai" aria-label="Permalink to &quot;Chính sách Bảo mật - Các loại&quot;">​</a></h2><ol><li><p><strong>Chính sách buông lỏng (Promiscuous Policy)</strong> - Chính sách này thường không có hạn chế nào về sử dụng tài nguyên hệ thống.</p></li><li><p><strong>Chính sách cho phép (Permissive Policy)</strong> - Chính sách này bắt đầu rộng mở và chỉ chặn các dịch vụ/tấn công hoặc hành vi nguy hiểm đã biết. Loại chính sách này phải được cập nhật thường xuyên để duy trì hiệu quả.</p></li><li><p><strong>Chính sách thận trọng (Prudent Policy)</strong> - Chính sách này cung cấp bảo mật tối đa trong khi cho phép các nguy hiểm đã biết nhưng cần thiết. Loại chính sách này sẽ chặn tất cả dịch vụ và chỉ các dịch vụ an toàn/cần thiết được bật riêng lẻ. Mọi thứ đều được ghi nhật ký.</p></li><li><p><strong>Chính sách hoang tưởng (Paranoid Policy)</strong> - Chính sách này cấm mọi thứ. Không có kết nối internet hoặc sử dụng internet bị hạn chế nghiêm ngặt.</p></li></ol><h2 id="chinh-sach-bao-mat-cac-buoc-tao" tabindex="-1">Chính sách Bảo mật - Các bước tạo <a class="header-anchor" href="#chinh-sach-bao-mat-cac-buoc-tao" aria-label="Permalink to &quot;Chính sách Bảo mật - Các bước tạo&quot;">​</a></h2><ol><li>Thực hiện Đánh giá Rủi ro</li><li>Sử dụng Tiêu chuẩn và Khung bảo mật làm hướng dẫn</li><li>Lấy ý kiến Ban quản lý và Nhân viên</li><li>Thực thi chính sách. Sử dụng hình phạt cho việc không tuân thủ</li><li>Xuất bản dự thảo cuối cùng cho toàn bộ tổ chức.</li><li>Yêu cầu tất cả nhân viên đọc/ký rằng họ đã hiểu chính sách</li><li>Sử dụng công cụ để hỗ trợ thực thi chính sách</li><li>Đào tạo nhân viên</li><li>Đánh giá và cập nhật thường xuyên</li></ol><h2 id="quy-trinh-quan-ly-su-co" tabindex="-1"><u>Quy trình Quản lý Sự cố</u> <a class="header-anchor" href="#quy-trinh-quan-ly-su-co" aria-label="Permalink to &quot;&lt;u&gt;Quy trình Quản lý Sự cố&lt;/u&gt;&quot;">​</a></h2><p><em>Sự cố là một sự kiện có thể dẫn đến mất mát hoặc gián đoạn hoạt động, dịch vụ hoặc chức năng của tổ chức.</em></p><p><em><strong>Quản lý sự cố</strong> là thuật ngữ mô tả các hoạt động của tổ chức để xác định, phân tích và sửa lỗi để ngăn ngừa sự tái diễn trong tương lai.</em></p><ol><li><strong>Chuẩn bị:</strong> Chọn người, gán quy tắc, xác định công cụ để xử lý sự cố.</li><li><strong>Phát hiện &amp; Phân tích:</strong> Xác định sự cố đã xảy ra (IDS, SIEM, AV, Ai đó báo cáo, v.v).</li><li><strong>Phân loại và Ưu tiên:</strong></li><li><strong>Thông báo:</strong> Xác định sự cố nhỏ và lớn; ai và cách thông báo sự cố.</li><li><strong>Khống chế:</strong> Hạn chế thiệt hại; Cách ly máy chủ; Liên hệ chủ hệ thống.</li><li><strong>Điều tra Pháp y:</strong> Điều tra nguyên nhân gốc của sự cố sử dụng công cụ pháp y; Nhật ký hệ thống, bộ nhớ thời gian thực, nhật ký thiết bị mạng, nhật ký ứng dụng, v.v;</li><li><strong>Loại bỏ &amp; Phục hồi:</strong> Loại bỏ nguyên nhân sự cố; Vá nếu cần. Phục hồi: đưa vào sản xuất; Giám sát hệ thống bị ảnh hưởng.</li><li><strong>Hoạt động sau sự cố:</strong> Ghi lại những gì đã xảy ra và tại sao; Chuyển giao kiến thức.</li></ol><h3 id="nhiem-vu-cua-đoi-ung-pho-su-co" tabindex="-1">Nhiệm vụ của Đội Ứng phó Sự cố <a class="header-anchor" href="#nhiem-vu-cua-đoi-ung-pho-su-co" aria-label="Permalink to &quot;Nhiệm vụ của Đội Ứng phó Sự cố&quot;">​</a></h3><ol><li>Quản lý các vấn đề bảo mật bằng cách tiếp cận chủ động đối với lỗ hổng bảo mật của khách hàng</li><li>Phát triển hoặc đánh giá các quy trình và thủ tục phải được tuân theo</li><li>Quản lý phản ứng đối với sự cố và đảm bảo tất cả các thủ tục được tuân theo đúng cách để giảm thiểu và kiểm soát thiệt hại</li><li>Xác định và phân tích những gì đã xảy ra trong sự cố, bao gồm tác động và mối đe dọa</li><li>Cung cấp một điểm liên hệ duy nhất để báo cáo sự cố và vấn đề bảo mật</li><li>Đánh giá các thay đổi trong yêu cầu pháp lý và quy định để đảm bảo tất cả các quy trình và thủ tục hợp lệ</li><li>Đánh giá các kiểm soát hiện có và đề xuất các bước và công nghệ để ngăn ngừa sự cố tương lai</li><li>Thiết lập mối quan hệ với cơ quan thực thi pháp luật địa phương, cơ quan chính phủ, đối tác chính và nhà cung cấp</li></ol><h3 id="siem-quan-ly-thong-tin-va-su-kien-bao-mat" tabindex="-1">SIEM - Quản lý Thông tin và Sự kiện Bảo mật <a class="header-anchor" href="#siem-quan-ly-thong-tin-va-su-kien-bao-mat" aria-label="Permalink to &quot;SIEM - Quản lý Thông tin và Sự kiện Bảo mật&quot;">​</a></h3><p align="center"><img width="90%" src="https://secureops.com/wp-content/uploads/2020/01/components-of-siem.jpg"></p><p><em>Thu thập dữ liệu từ mạng, bao gồm tệp nhật ký, bắt lưu lượng, tin nhắn SNMP, v.v., từ mọi máy chủ trên mạng. SIEM có thể thu thập tất cả dữ liệu này vào một vị trí tập trung và tương quan để phân tích tìm kiếm vấn đề bảo mật và hiệu suất, cũng như xu hướng tiêu cực tất cả trong thời gian thực.</em></p><ul><li><p><strong>Tổng hợp (Aggregation)</strong>: Thu thập dữ liệu từ các nguồn khác nhau và tổ chức dữ liệu thành một định dạng duy nhất. Bất kỳ thiết bị nào trong hệ thống SIEM thu thập dữ liệu được gọi là collector hoặc aggregator.</p></li><li><p><strong>Tương quan (Correlation)</strong>: Là logic xem xét dữ liệu từ các nguồn khác nhau và có thể đưa ra xác định về các sự kiện diễn ra trên mạng của bạn. (Có thể là in-band hoặc out-of-band, tùy thuộc vào vị trí của NIDS/NIPS).</p><ul><li><strong>Cảnh báo</strong> - Để thông báo nếu có gì đó xấu xảy ra.</li><li><strong>Kích hoạt</strong> - Vượt quá ngưỡng.</li></ul></li><li><p><strong>Chuẩn hóa (Normalization)</strong>: Sẽ thực sự tạo nhiều bảng / tổ chức theo cách dữ liệu trở nên hiệu quả hơn và cho phép công cụ phân tích và báo cáo hoạt động tốt hơn.</p></li><li><p><strong>WORM - Write Once Read Many (Ghi một lần Đọc nhiều lần)</strong>: Khái niệm là tệp nhật ký quý giá, và很多时候 bạn có thể muốn xem chúng theo cách lưu trữ, vì vậy chúng ta có thể sử dụng phương tiện quang như ổ WORM để lưu trữ chúng.</p></li></ul><h4 id="cong-cu-siem-pho-bien-nhat" tabindex="-1">Công cụ SIEM Phổ biến nhất: <a class="header-anchor" href="#cong-cu-siem-pho-bien-nhat" aria-label="Permalink to &quot;Công cụ SIEM Phổ biến nhất:&quot;">​</a></h4><ul><li><p><strong><a href="https://www.splunk.com/" target="_blank" rel="noreferrer">Splunk</a></strong><img src="https://www.splunk.com/content/dam/splunk2/images/screenshots/platform-journey/conflaunch/SS-UI-Light-Mode-frame.png" alt="splunk"></p></li><li><p><strong><a href="https://www.microfocus.com/en-us/products/siem-security-information-event-management/overview" target="_blank" rel="noreferrer">ArcSight</a></strong><img src="https://i.ytimg.com/vi/N7J0EwdbKF0/maxresdefault.jpg" alt="arcsight"></p></li><li><p><strong><a href="https://www.elastic.co/what-is/elk-stack" target="_blank" rel="noreferrer">ELK - Elastic Search, Log Stash and Kibana</a> (Mã nguồn mở)</strong><img src="https://i.imgur.com/lydtCwn.png" alt="elk"></p></li></ul><h2 id="quan-ly-danh-tinh-va-truy-cap" tabindex="-1"><u>Quản lý Danh tính và Truy cập</u> <a class="header-anchor" href="#quan-ly-danh-tinh-va-truy-cap" aria-label="Permalink to &quot;&lt;u&gt;Quản lý Danh tính và Truy cập&lt;/u&gt;&quot;">​</a></h2><blockquote><p><strong>Xác định, Xác thực, Ủy quyền</strong>, và <strong>Kế toán</strong> hoạt động cùng nhau để quản lý tài sản một cách bảo mật.</p></blockquote><h3 id="_1-xac-đinh-identification" tabindex="-1">1. <strong>Xác định (Identification)</strong> <a class="header-anchor" href="#_1-xac-đinh-identification" aria-label="Permalink to &quot;1. **Xác định (Identification)**&quot;">​</a></h3><p><em>Thông tin trên thông tin đăng nhập xác định người dùng.</em></p><ul><li><strong>Ví dụ</strong>: <ul><li>Tên, tên người dùng, số ID, số nhân viên, SSN, v.v.</li></ul></li></ul><h3 id="_2-xac-thuc-authentication" tabindex="-1">2. <strong>Xác thực (Authentication)</strong> <a class="header-anchor" href="#_2-xac-thuc-authentication" aria-label="Permalink to &quot;2. **Xác thực (Authentication)**&quot;">​</a></h3><p><em>“Chứng minh bạn là Người dùng hợp pháp.&quot; – Luôn nên được thực hiện với Xác thực đa yếu tố!</em></p><ul><li><strong>Các yếu tố Xác thực:</strong><ul><li>Thứ bạn <strong>biết</strong> (ví dụ - mật khẩu)</li><li>Thứ bạn <strong>có</strong> (ví dụ - thẻ thông minh)</li><li>Thứ bạn <strong>là</strong> (ví dụ - vân tay)</li><li>Thứ bạn <strong>làm</strong> (ví dụ - mẫu hình android; chữ ký thủ công)</li><li><strong>Nơi</strong> bạn ở (ví dụ - vị trí địa lý)</li></ul></li></ul><blockquote><p>🛑 <strong>Xác thực đa yếu tố</strong> <em>thường sử dụng hai trong số các ví dụ này (ví dụ - Thứ bạn <strong>Biết(1)</strong> và Thứ bạn <strong>Có(2)</strong>, không bao giờ cùng một loại</em></p></blockquote><h3 id="_3-khai-niem-uy-quyen-authorization" tabindex="-1">3. Khái niệm Ủy quyền (Authorization) <a class="header-anchor" href="#_3-khai-niem-uy-quyen-authorization" aria-label="Permalink to &quot;3. Khái niệm Ủy quyền (Authorization)&quot;">​</a></h3><p><em>Bạn được phép truy cập gì – Chúng ta sử dụng mô hình Kiểm soát Truy cập, cái gì và cách triển khai phụ thuộc vào tổ chức và mục tiêu bảo mật của chúng ta.</em></p><ul><li><strong>Quyền hạn (Permissions)</strong>: <ul><li>Áp dụng cho tài nguyên</li></ul></li><li><strong>Quyền</strong> / <strong>Đặc quyền (Rights / Privileges)</strong>: <ul><li>Gán ở cấp hệ thống</li></ul></li><li><strong>Chiến lược ủy quyền</strong>: <ul><li>Đặc quyền tối thiểu (Least privileged)</li><li>Phân chia nhiệm vụ (Separation of Duties)</li></ul></li></ul><h3 id="_4-ke-toan-accounting" tabindex="-1">4. Kế toán (Accounting) <a class="header-anchor" href="#_4-ke-toan-accounting" aria-label="Permalink to &quot;4. Kế toán (Accounting)&quot;">​</a></h3><p><em>Truy vết Hành động đến Danh tính của Đối tượng:</em></p><ul><li>Chứng minh ai/cái gì đã thực hiện hành động (không từ chối); Ghi nhật ký</li></ul><h3 id="mo-hinh-kiem-soat-truy-cap" tabindex="-1">Mô hình Kiểm soát Truy cập <a class="header-anchor" href="#mo-hinh-kiem-soat-truy-cap" aria-label="Permalink to &quot;Mô hình Kiểm soát Truy cập&quot;">​</a></h3><p align="center"><img width="80%" src="https://security-architect.com/wp-content/uploads/FGA.png"></p><ul><li><strong>Kiểm soát Truy cập Bắt buộc (MAC - Mandatory Access Control)</strong>: <ul><li>Mỗi đối tượng được gán một <strong>nhãn</strong><ul><li>Mật, bí mật, tối mật, v.v</li></ul></li><li>Quản trị viên quyết định ai được truy cập mức bảo mật nào; Người dùng không thể thay đổi các cài đặt này</li><li>Được sử dụng trên hệ thống cũ (ví dụ: Thông tin Chính phủ Tối mật)</li></ul></li><li><strong>Kiểm soát Truy cập Tùy ý (DAC - Discretionary Access Control)</strong>: <ul><li>Được sử dụng trong hầu hết hệ điều hành</li><li>Chủ sở hữu dữ liệu xác định truy cập</li><li>Kiểm soát truy cập rất linh hoạt; Bảo mật rất yếu</li></ul></li><li><strong>Kiểm soát Truy cập dựa trên Vai trò (RBAC - Role-based Access Control)</strong>: <ul><li>Truy cập vào tài nguyên được xác định bởi một tập hợp quy tắc được xác định bởi vai trò trong tổ chức/chức năng công việc của bạn (Quản lý, Giám đốc, v.v)</li><li>Quản trị viên cung cấp truy cập dựa trên vai trò của người dùng <ul><li>Quyền được hưởng một cách ngầm thay vì rõ ràng</li></ul></li><li>Trong Windows, sử dụng <strong>Groups</strong> để cung cấp kiểm soát truy cập dựa trên vai trò <ul><li>Ví dụ: Admin Groups --&gt; Rights and Perms,</li><li>Sales Group --&gt; Rights and Perms</li></ul></li></ul></li></ul><blockquote><p>⚠️ <strong>Truy cập được xác định bởi ACL, Danh sách Kiểm soát Truy cập (Access Control List)</strong>. ⚠️ <strong>Từ chối ngầm (Implicit deny)</strong> ngăn truy cập trừ khi được phép cụ thể.</p></blockquote><h2 id="ngan-ngua-mat-mat-du-lieu-dlp" tabindex="-1">Ngăn ngừa Mất mát Dữ liệu (DLP) <a class="header-anchor" href="#ngan-ngua-mat-mat-du-lieu-dlp" aria-label="Permalink to &quot;Ngăn ngừa Mất mát Dữ liệu (DLP)&quot;">​</a></h2><p>Ngăn ngừa Mất mát Dữ liệu (DLP) là thực hành <strong>phát hiện và ngăn chặn vi phạm dữ liệu, rò rỉ hoặc phá hủy không mong muốn dữ liệu nhạy cảm</strong>. Tổ chức sử dụng DLP để bảo vệ và bảo mật dữ liệu của họ và tuân thủ quy định.</p><ul><li>Thuật ngữ DLP đề cập đến việc bảo vệ tổ chức chống lại cả mất mát dữ liệu và ngăn chặn rò rỉ dữ liệu.</li></ul><h4 id="to-chuc-thuong-su-dung-dlp-đe" tabindex="-1">Tổ chức thường sử dụng DLP để: <a class="header-anchor" href="#to-chuc-thuong-su-dung-dlp-đe" aria-label="Permalink to &quot;Tổ chức thường sử dụng DLP để:&quot;">​</a></h4><ul><li>Bảo vệ Thông tin Cá nhân Nhận dạng (PII) và tuân thủ quy định liên quan</li><li>Bảo vệ Sở hữu Trí tuệ quan trọng cho tổ chức</li><li>Đạt được khả năng hiển thị dữ liệu trong tổ chức lớn</li><li>Bảo mật lực lượng lao động di động và thực thi bảo mật trong môi trường Mang Thiết bị Riêng (BYOD)</li><li>Bảo mật dữ liệu trên hệ thống đám mây từ xa</li></ul><p align="center"><img width="90%" src="https://miro.medium.com/max/720/1*FG9LR51eySVRQJUjhVv-9A.png"></p><h2 id="sao-luu-du-lieu" tabindex="-1">Sao lưu Dữ liệu <a class="header-anchor" href="#sao-luu-du-lieu" aria-label="Permalink to &quot;Sao lưu Dữ liệu&quot;">​</a></h2><p>Sao lưu dữ liệu đóng vai trò quan trọng trong duy trì tính liên tục kinh doanh bằng cách giúp tổ chức phục hồi từ thảm họa CNTT, vi phạm bảo mật, lỗi ứng dụng, lỗi con người, v.v.</p><p>Tất cả các quy định tuân thủ như COBIT, SSAE, SOCII, PCI-DSS, HIPPA, SOX, FINRA, FISMA, GDPR, v.v. yêu cầu doanh nghiệp duy trì sao lưu dữ liệu quan trọng trong thời gian quy định.</p><h3 id="chien-luoc-sao-luu" tabindex="-1">Chiến lược Sao lưu <a class="header-anchor" href="#chien-luoc-sao-luu" aria-label="Permalink to &quot;Chiến lược Sao lưu&quot;">​</a></h3><ol><li>Xác định dữ liệu kinh doanh quan trọng</li><li>Chọn phương tiện sao lưu</li><li>Chọn công nghệ sao lưu</li><li>Chọn cấp RAID phù hợp</li><li>Chọn phương pháp sao lưu phù hợp</li></ol><h3 id="_3-phuong-phap-sao-luu" tabindex="-1">3 Phương pháp sao lưu <a class="header-anchor" href="#_3-phuong-phap-sao-luu" aria-label="Permalink to &quot;3 Phương pháp sao lưu&quot;">​</a></h3><h4 id="_1-sao-luu-lanh-cold-backup-🔵" tabindex="-1">1. Sao lưu lạnh (Cold backup) 🔵 <a class="header-anchor" href="#_1-sao-luu-lanh-cold-backup-🔵" aria-label="Permalink to &quot;1. Sao lưu lạnh (Cold backup) 🔵&quot;">​</a></h4><img width="40%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/29c5e018095b135baec32aaece84a900a43b23ca/cc-cold.png"><ul><li><strong>Trang trống, không phần cứng, không dữ liệu, không người</strong></li><li><strong>Mất vài tuần để đưa vào hoạt động</strong></li><li>Không gian văn phòng cơ bản (ví dụ tòa nhà, ghế, điều hòa...)</li><li>Không thiết bị vận hành</li><li>Địa điểm phục hồi rẻ nhất</li></ul><h4 id="_2-sao-luu-am-warm-backup-🟡" tabindex="-1">2. Sao lưu ấm (Warm backup) 🟡 <a class="header-anchor" href="#_2-sao-luu-am-warm-backup-🟡" aria-label="Permalink to &quot;2. Sao lưu ấm (Warm backup) 🟡&quot;">​</a></h4><img width="40%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/29c5e018095b135baec32aaece84a900a43b23ca/cc-warm.png"><ul><li><strong>Nằm giữa lạnh và nóng - Đủ để bắt đầu (Phòng lớn với không gian rack, bạn mang phần cứng đến)</strong></li><li>Phần cứng đã sẵn sàng và chờ đợi - bạn mang phần mềm và dữ liệu đến</li><li><strong>Mất vài ngày để đưa vào hoạt động</strong></li><li>Thiết bị vận hành nhưng ít hoặc không có dữ liệu</li></ul><h4 id="_3-sao-luu-nong-hot-backup-🔴" tabindex="-1">3. Sao lưu nóng (Hot backup) 🔴 <a class="header-anchor" href="#_3-sao-luu-nong-hot-backup-🔴" aria-label="Permalink to &quot;3. Sao lưu nóng (Hot backup) 🔴&quot;">​</a></h4><img width="40%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/29c5e018095b135baec32aaece84a900a43b23ca/cc-hot.png"><ul><li><strong>Bản sao chính xác của hệ thống sản xuất</strong></li><li>Ứng dụng và phần mềm được cập nhật liên tục</li><li>Bật công tắc và mọi thứ di chuyển</li><li><strong>Mất vài giờ để đưa vào hoạt động</strong></li><li>Đồng bộ hóa thời gian thực</li><li>Gần như tất cả dữ liệu sẵn sàng - thường chỉ cần cập nhật nhanh</li><li>Rất đắt</li></ul><h2 id="kiem-thu-xam-nhap-co-ban" tabindex="-1"><u>Kiểm thử Xâm nhập - Cơ bản</u> <a class="header-anchor" href="#kiem-thu-xam-nhap-co-ban" aria-label="Permalink to &quot;&lt;u&gt;Kiểm thử Xâm nhập - Cơ bản&lt;/u&gt;&quot;">​</a></h2><blockquote><p><strong>Chủ đề này sẽ được giới thiệu chi tiết trong <a href="https://github.com/Samsar4/CEH-v10-Study-Guide/blob/master/modules/14-Pentesting.md" target="_blank" rel="noreferrer">Chapter 14 - Pentesting</a>.</strong></p></blockquote><p><em>Kiểm thử xâm nhập, thường được gọi là pen test, pentest hoặc hacking đạo đức, là một cuộc tấn công mạng mô phỏng được ủy quyền vào hệ thống máy tính, được thực hiện để đánh giá bảo mật của hệ thống.</em></p><blockquote><p>⚠️ <strong>Không nhầm lẫn với đánh giá lỗ hổng.</strong></p></blockquote><ul><li>Được xác định rõ ràng, kiểm thử toàn diện các kiểm soát bảo mật</li><li>Các giai đoạn <ul><li><strong>Chuẩn bị</strong> - Hợp đồng và nhóm được xác định</li><li><strong>Đánh giá</strong> - Tất cả các giai đoạn hacking (do thám, quét, tấn công, v.v.)</li><li><strong>Sau đánh giá</strong> - Báo cáo &amp; kết luận</li></ul></li><li>Các loại <ul><li><strong>Black Box</strong> - Thực hiện mà không có kiến thức nào về hệ thống hoặc mạng.</li><li><strong>White Box</strong> - Khi kẻ tấn công có kiến thức đầy đủ về hệ thống được cung cấp bởi chủ sở hữu/mục tiêu.</li><li><strong>Gray Box</strong> - Khi kẻ tấn công có một số kiến thức về hệ thống và/hoặc mạng</li></ul></li></ul><h2 id="luat-va-tieu-chuan" tabindex="-1">Luật và Tiêu chuẩn: <a class="header-anchor" href="#luat-va-tieu-chuan" aria-label="Permalink to &quot;Luật và Tiêu chuẩn:&quot;">​</a></h2><h3 id="tuan-thu-osstm" tabindex="-1"><strong>Tuân thủ OSSTM</strong> <a class="header-anchor" href="#tuan-thu-osstm" aria-label="Permalink to &quot;**Tuân thủ OSSTM**&quot;">​</a></h3><p><strong>&quot;Open Source Security Testing Methodology Manual&quot;</strong> (Sổ tay Phương pháp Kiểm tra Bảo mật Mã nguồn mở) được duy trì bởi ISECOM, xác định ba loại tuân thủ.</p><ul><li><p><strong>Lập pháp</strong> - Giải quyết quy định chính phủ (Như SOX và HIPAA).</p></li><li><p><strong>Hợp đồng</strong> - Giải quyết yêu cầu ngành / nhóm (Như PCI DSS).</p></li><li><p><strong>Dựa trên tiêu chuẩn</strong> - Giải quyết các thực hành phải được tuân theo bởi thành viên của nhóm/tổ chức nhất định (Như ITIL, ISO và OSSTMM).</p></li><li><p><strong>Kiểm soát OSSTM</strong></p><ul><li><strong>OSSTM Class A - Kiểm soát Tương tác</strong><ul><li><em>Xác thực</em> - Cung cấp xác định và ủy quyền dựa trên thông tin đăng nhập.</li><li><em>Bồi thường</em> - Cung cấp bảo vệ hợp đồng chống mất mát hoặc thiệt hại.</li><li><em>Phục tùng</em> - Đảm bảo rằng tương tác xảy ra theo quy trình được xác định bởi chủ tài sản.</li><li><em>Tính liên tục</em> - Duy trì tính tương tác với tài nguyên nếu xảy ra hỏng hoặc lỗi.</li><li><em>Khả năng phục hồi</em> - Bảo vệ tài nguyên khỏi hỏng hóc và lỗi.</li></ul></li></ul></li><li><p><strong>OSSTM Class B - Kiểm soát Quy trình</strong></p><ul><li><em>Không từ chối</em> - Ngăn người tham gia từ chối hành động của họ</li><li><em>Bảo mật</em> - Đảm bảo rằng chỉ người tham gia biết về tài nguyên</li><li><em>Quyền riêng tư</em> - Đảm bảo rằng chỉ người tham gia có quyền truy cập tài nguyên</li><li><em>Toàn vẹn</em> - Đảm bảo rằng chỉ người tham gia biết khi tài nguyên và quy trình thay đổi</li><li><em>Báo động</em> - Thông báo cho người tham gia khi tương tác xảy ra</li></ul></li></ul><h3 id="pci-dss" tabindex="-1"><strong>PCI-DSS</strong> <a class="header-anchor" href="#pci-dss" aria-label="Permalink to &quot;**PCI-DSS**&quot;">​</a></h3><p><strong>&quot;Payment Card Industry Data Security Standard&quot;</strong> (Tiêu chuẩn Bảo mật Dữ liệu Ngành Thanh toán) Tiêu chuẩn cho các tổ chức xử lý Thẻ tín dụng, Thẻ ATM và các thẻ POS khác.</p><h3 id="iso-27001" tabindex="-1"><strong>ISO 27001</strong> <a class="header-anchor" href="#iso-27001" aria-label="Permalink to &quot;**ISO 27001**&quot;">​</a></h3><p>Tiêu chuẩn Quốc tế này được chuẩn bị để cung cấp các yêu cầu thiết lập, triển khai, duy trì và cải thiện liên tục hệ thống quản lý bảo mật thông tin.</p><h3 id="iso-27002-va-17799" tabindex="-1"><strong>ISO 27002 VÀ 17799</strong> <a class="header-anchor" href="#iso-27002-va-17799" aria-label="Permalink to &quot;**ISO 27002 VÀ 17799**&quot;">​</a></h3><p>Dựa trên BS799 nhưng tập trung vào mục tiêu bảo mật và cung cấp kiểm soát bảo mật dựa trên thực tiễn tốt nhất của ngành.</p><h3 id="hipaa" tabindex="-1"><strong>HIPAA</strong> <a class="header-anchor" href="#hipaa" aria-label="Permalink to &quot;**HIPAA**&quot;">​</a></h3><p><strong>&quot;Health Insurance Portability and Accountability Act&quot;</strong> (Đạo luật Di chuyển và Trách nhiệm Bảo hiểm Y tế) luật thiết lập tiêu chuẩn quyền riêng tư để bảo vệ hồ sơ y tế bệnh nhân và thông tin sức khỏe được chia sẻ giữa bác sĩ, bệnh viện và nhà cung cấp bảo hiểm.</p><h3 id="sox" tabindex="-1"><strong>SOX</strong> <a class="header-anchor" href="#sox" aria-label="Permalink to &quot;**SOX**&quot;">​</a></h3><p><strong>&quot;Sarbanes-Oxley Act&quot;</strong> (Đạo luật Sarbanes-Oxley) Luật yêu cầu các công ty giao dịch công khai nộp cho kiểm toán độc lập và công bố đúng thông tin tài chính.</p><h3 id="dmca" tabindex="-1">DMCA <a class="header-anchor" href="#dmca" aria-label="Permalink to &quot;DMCA&quot;">​</a></h3><p><strong>&quot;The Digital Millennium Copyright Act&quot;</strong> (Đạo luật Bản quyền Thiên niên kỷ Kỹ thuật số) là luật bản quyền Hoa Kỳ năm 1998 thực hiện hai hiệp ước năm 1996 của Tổ chức Sở hữu Trí tuệ Thế giới. Nó hình sự hóa việc sản xuất và phân phối công nghệ, thiết bị hoặc dịch vụ nhằm mục đích lách các biện pháp kiểm soát truy cập vào tác phẩm có bản quyền.</p><h3 id="fisma" tabindex="-1"><strong>FISMA</strong> <a class="header-anchor" href="#fisma" aria-label="Permalink to &quot;**FISMA**&quot;">​</a></h3><p><strong>&quot;Federal Information Security Modernization Act Of 2002&quot;</strong> (Đạo luật Hiện đại hóa Bảo mật Thông tin Liên bang năm 2002) Luật được cập nhật năm 2004 để mã hóa quyền hạn của Bộ An ninh Nội địa liên quan đến triển khai chính sách bảo mật thông tin. <em>(Dành cho cơ quan chính phủ)</em></p><h3 id="nist-800-53" tabindex="-1"><strong>NIST-800-53</strong> <a class="header-anchor" href="#nist-800-53" aria-label="Permalink to &quot;**NIST-800-53**&quot;">​</a></h3><p>Danh mục kiểm soát bảo mật và quyền riêng tư cho hệ thống thông tin liên bang, được tạo để hỗ trợ triển khai FISMA.</p><h3 id="fitara" tabindex="-1"><strong>FITARA</strong> <a class="header-anchor" href="#fitara" aria-label="Permalink to &quot;**FITARA**&quot;">​</a></h3><p><strong>&quot;Federal Information Technology Acquisition Reform Act&quot;</strong> (Đạo luật Cải cách Mua sắm Công nghệ Thông tin Liên bang) Dự luật năm 2013 nhằm thay đổi khung xác định cách chính phủ Mỹ mua công nghệ.</p><h3 id="cobit" tabindex="-1"><strong>COBIT</strong> <a class="header-anchor" href="#cobit" aria-label="Permalink to &quot;**COBIT**&quot;">​</a></h3><p><strong>&quot;Control Object for Information and Related Technology&quot;</strong> (Đối tượng Kiểm soát cho Thông tin và Công nghệ Liên quan) Khung quản trị CNTT và bộ công cụ, được tạo bởi ISACA và ITGI</p><h3 id="glba" tabindex="-1"><strong>GLBA</strong> <a class="header-anchor" href="#glba" aria-label="Permalink to &quot;**GLBA**&quot;">​</a></h3><p><strong>&quot;U.S Gramm-Leach-Bliley Act&quot;</strong> (Đạo luật Gramm-Leach-Bliley của Mỹ) Luật bảo vệ tính bảo mật và toàn vẹn của thông tin cá nhân được thu thập bởi tổ chức tài chính.</p><h3 id="csirt" tabindex="-1"><strong>CSIRT</strong> <a class="header-anchor" href="#csirt" aria-label="Permalink to &quot;**CSIRT**&quot;">​</a></h3><p><strong>&quot;Computer Security Incident Response Team&quot;</strong> (Đội Ứng phó Sự cố Bảo mật Máy tính) CSIRT cung cấp một điểm liên hệ duy nhất khi báo cáo sự cố bảo mật máy tính</p><h3 id="itil" tabindex="-1"><strong>ITIL</strong> <a class="header-anchor" href="#itil" aria-label="Permalink to &quot;**ITIL**&quot;">​</a></h3><p><strong>&quot;Information Technology Infrastructure Library&quot;</strong> (Thư viện Cơ sở hạ tầng Công nghệ Thông tin) - Khung vận hành được phát triển vào thập niên 80 tiêu chuẩn hóa các thủ tục quản lý CNTT</p>',185)]))}const p=t(a,[["render",o]]);export{m as __pageData,p as default};
